@@ -38047,9 +38047,55 @@ impl Connection {
             self.materialize_with_clause(insert.with.as_ref(), params, &mut temp_tables)?;
             let mut stripped = insert.clone();
             stripped.with = None;
-            self.with_compiled_cache_bypass(|| {
-                self.execute_statement(&Statement::Insert(stripped), params)
-            })
+            // Route through the interpreted INSERT fallback instead of the
+            // full dispatch. The VDBE codegen's find_table cannot locate
+            // CTE temp tables that are only in the connection's live schema,
+            // causing "no such table" errors. The interpreted fallback
+            // materializes the SELECT source rows (which CAN find the temp
+            // table via the connection's schema) and inserts them row-by-row.
+            if let InsertSource::Select(ref select_stmt) = stripped.source {
+                let source_rows = self.execute_statement(
+                    &Statement::Select(select_stmt.as_ref().clone()),
+                    params,
+                )?;
+                if source_rows.is_empty() {
+                    self.reset_statement_change_count();
+                    return Ok(Vec::new());
+                }
+                let col_values: Vec<Vec<SqliteValue>> = source_rows
+                    .into_iter()
+                    .map(|row| row.values)
+                    .collect();
+                let table_name = &stripped.table.name;
+                for vals in &col_values {
+                    let placeholders = (0..vals.len()).map(|_| "?").collect::<Vec<_>>().join(",");
+                    let conflict = match stripped.or_conflict {
+                        Some(fsqlite_ast::ConflictAction::Replace) => "OR REPLACE ",
+                        Some(fsqlite_ast::ConflictAction::Ignore) => "OR IGNORE ",
+                        Some(fsqlite_ast::ConflictAction::Abort) => "OR ABORT ",
+                        Some(fsqlite_ast::ConflictAction::Fail) => "OR FAIL ",
+                        Some(fsqlite_ast::ConflictAction::Rollback) => "OR ROLLBACK ",
+                        None => "",
+                    };
+                    let insert_sql = if stripped.columns.is_empty() {
+                        format!(
+                            "INSERT {conflict}INTO {table_name} VALUES ({placeholders})",
+                        )
+                    } else {
+                        let cols = stripped.columns.join(", ");
+                        format!(
+                            "INSERT {conflict}INTO {table_name} ({cols}) VALUES ({placeholders})",
+                        )
+                    };
+                    self.execute_with_params(&insert_sql, vals)?;
+                }
+                self.record_statement_changes(col_values.len());
+                Ok(Vec::new())
+            } else {
+                self.with_compiled_cache_bypass(|| {
+                    self.execute_statement(&Statement::Insert(stripped), params)
+                })
+            }
         })();
         self.cleanup_cte_tables(&temp_tables);
         self.set_reject_mem_fallback(prev_reject);
